"""Элементы-разделители: горизонтальная и вертикальная линии. Настройки в UI_SEPARATOR (template/styles)."""from __future__ import annotationsimport tkinter as tkfrom src.gui.template.styles import PALETTE, UI_SEPARATORdef gui_element_separator(parent: tk.Misc) -> tk.Frame:    """    Горизонтальная линия. Цвет, толщина и отступы сверху/снизу из UI_SEPARATOR.    Размещать в grid/pack со sticky=tk.EW.    """    p = PALETTE    s = UI_SEPARATOR    pad = s["padding_horizontal_px"]    container = tk.Frame(parent, bg=p["bg_surface"], height=s["width_px"] + 2 * pad)    line = tk.Frame(container, height=s["width_px"], bg=s["color"])    line.pack(fill=tk.X, pady=(pad, pad))    container.pack_propagate(False)    return containerdef gui_element_separator_vert(parent: tk.Misc) -> tk.Frame:    """    Вертикальная линия. Цвет, толщина и отступы слева/справа из UI_SEPARATOR.    Возвращает контейнер (линия внутри с padding_vertical_px). Размещать в grid с sticky=tk.NS.    """    p = PALETTE    s = UI_SEPARATOR    pad = s["padding_vertical_px"]    total_w = s["width_px"] + 2 * pad    container = tk.Frame(parent, width=total_w, bg=p["bg_surface"])    container.pack_propagate(False)    line = tk.Frame(container, width=s["width_px"], bg=s["color"])    line.pack(fill=tk.Y, padx=(pad, pad), expand=True)    return container